// LimmConfig.swift — limm VPN constants + per-device UID
// Token is injected at build time via LimmSecrets.swift (gitignored, generated by CI).

import Foundation

enum LimmConfig {
    // API
    static let apiBase      = "https://limm.space/api"
    static let subURL       = "https://limm.space/vpn/sub"
    // proxy-vpn fork (V2rayU-based) has its own info file: proxy-mac-info.json.
    // Hiddify fork (vpn-mac) uses /vpn/mac/latest. Do NOT mix them up.
    static let releasesURL  = "https://limm.space/vpn/proxy-mac/latest"

    // Checkin
    static let checkinInterval: TimeInterval = 900   // 15 min
    static let clientKind   = "macos"
    static let clientLabel  = "limm-mac"
    // format "version+hash4" — parsed by dashboard buildTag() → shows #hash
    static let appVersion   = "\(LimmBuildInfo.version)+\(LimmBuildInfo.commit)"

    // Server (for L0-L2 raw probes)
    static let serverIP     = "45.95.175.170"
    static let serverPort   = 443

    // UserDefaults keys
    static let uidKey            = "limmClientUID"
    static let checkinEnabledKey = "limmCheckinEnabled"

    // Stable per-device UUID (auto-generated on first launch)
    static func clientUID() -> String {
        let d = UserDefaults.standard
        if let uid = d.string(forKey: uidKey), !uid.isEmpty { return uid }
        let uid = UUID().uuidString.lowercased()
        d.set(uid, forKey: uidKey)
        return uid
    }

    // Build-time token from LimmSecrets.swift
    static var token: String { LimmSecrets.monitorToken }
}
